 1	import React, { FC } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { isEmpty } from '@kubevirt-utils/utils/utils';
 5	import { SelectGroup, SelectOption } from '@patternfly/react-core';
 6	
 7	import { NO_RESULTS } from '../utils/constants';
 8	import { EnhancedSelectOptionProps } from '../utils/types';
 9	
10	import InlineFilterSelectOption from './InlineFilterSelectOption';
11	
12	type InlineFilterSelectOptionsProps = {
13	  filterOptions: EnhancedSelectOptionProps[];
14	  filterValue: string;
15	  focusedItemIndex: number;
16	  groupedOptions: Record<string, EnhancedSelectOptionProps[]>;
17	};
18	const InlineFilterSelectOptions: FC<InlineFilterSelectOptionsProps> = ({
19	  filterOptions,
20	  filterValue,
21	  focusedItemIndex,
22	  groupedOptions,
23	}) => {
24	  const { t } = useKubevirtTranslation();
25	  if (isEmpty(filterOptions)) {
26	    return (
27	      <SelectOption isDisabled value={NO_RESULTS}>
28	        {t('No results found for "{{value}}"', { value: filterValue })}
29	      </SelectOption>
30	    );
31	  }
32	
33	  if (groupedOptions) {
34	    return (
35	      <>
36	        {Object.entries(groupedOptions).map(([group, opts]) => (
37	          <SelectGroup key={group} label={group}>
38	            {opts.map((option, index) => (
39	              <InlineFilterSelectOption
40	                isFocused={focusedItemIndex === index}
41	                key={option.value}
42	                option={option}
43	              />
44	            ))}
45	          </SelectGroup>
46	        ))}
47	      </>
48	    );
49	  }
50	
51	  return (
52	    <>
53	      {filterOptions.map((option, index) => (
54	        <InlineFilterSelectOption
55	          isFocused={focusedItemIndex === index}
56	          key={option.value}
57	          option={option}
58	        />
59	      ))}
60	    </>
61	  );
62	};
63	
64	export default InlineFilterSelectOptions;

